from sentence_transformers import SentenceTransformer

# --- intfloat/multilingual-e5-large ---
e5 = SentenceTransformer("intfloat/multilingual-e5-large")

def embed_e5_queries(queries: list[str]) -> list[list[float]]:
    prefixed = [f"query: {q}" for q in queries]
    return e5.encode(prefixed, normalize_embeddings=True).tolist()

def embed_e5_passages(passages: list[str]) -> list[list[float]]:
    prefixed = [f"passage: {p}" for p in passages]
    return e5.encode(prefixed, normalize_embeddings=True).tolist()


# --- BAAI/bge-m3 via prompt_name parameter ---
bge = SentenceTransformer("BAAI/bge-m3")

def embed_bge_query(query: str) -> list[float]:
    # bge-m3 supports prompt_name argument (v2.3+)
    vec = bge.encode(
        [query],
        prompt_name="query",
        normalize_embeddings=True,
    )
    return vec[0].tolist()

def embed_bge_passages(passages: list[str]) -> list[list[float]]:
    return bge.encode(passages, normalize_embeddings=True).tolist()

from functools import lru_cache
from sentence_transformers import SentenceTransformer

@lru_cache(maxsize=4)
def get_model(model_name: str, device: str = "cpu") -> SentenceTransformer:
    """Load and cache model by name. Call once per process."""
    return SentenceTransformer(model_name, device=device)


